final:
module johnson_counter(
    input               clk,
    input               clr,

    output reg [4:0]    count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge clr or posedge dbg_halt) begin
    if (clr)
        count <= 5'b00000;
    else
        count <= {count[3:0], ~count[4]};
end

endmodule
